/**
 * OfflineIndicator Component
 *
 * Shows a subtle indicator when the app is offline.
 * Positioned in the header or as a floating badge.
 */

import React from 'react';
import { WifiOff } from 'lucide-react';
import { usePWA } from '../hooks/usePWA';

interface OfflineIndicatorProps {
  /** Position variant */
  variant?: 'badge' | 'inline';
  /** Additional CSS classes */
  className?: string;
}

export const OfflineIndicator: React.FC<OfflineIndicatorProps> = ({
  variant = 'badge',
  className = '',
}) => {
  const { isOffline } = usePWA();

  if (!isOffline) return null;

  if (variant === 'inline') {
    return (
      <div
        className={`flex items-center gap-1.5 text-amber-500 dark:text-amber-400 ${className}`}
        role="status"
        aria-live="polite"
      >
        <WifiOff className="w-4 h-4" />
        <span className="text-sm font-medium">Offline</span>
      </div>
    );
  }

  // Badge variant - floating indicator
  return (
    <div
      className={`
        fixed bottom-4 left-4 z-50
        flex items-center gap-2 px-3 py-2
        bg-amber-500/90 dark:bg-amber-600/90
        text-white rounded-lg shadow-lg
        backdrop-blur-sm
        animate-in fade-in slide-in-from-bottom-2
        ${className}
      `}
      role="status"
      aria-live="polite"
    >
      <WifiOff className="w-4 h-4" />
      <span className="text-sm font-medium">You're offline</span>
    </div>
  );
};

export default OfflineIndicator;

