import React, { useState } from 'react';
import { motion } from 'framer-motion';
import { formatDistanceToNow } from 'date-fns';
import { useSaveStatus } from '../stores/useSaveStatus';
import { AboutModal } from './AboutModal';
import { PrivacyModal } from './PrivacyModal';
import { SupportModal } from './SupportModal';

/**
 * Footer component with save status indicator, Privacy Policy, and About Us
 * Sticky footer at bottom with links, save status at bottom-right
 */
export const Footer: React.FC = () => {
  const { status, lastSaveTime } = useSaveStatus();
  const [showAboutModal, setShowAboutModal] = useState(false);
  const [showPrivacyModal, setShowPrivacyModal] = useState(false);
  const [showSupportModal, setShowSupportModal] = useState(false);

  // Simplified status text
  const getStatusText = () => {
    switch (status) {
      case 'saving':
        return 'Saving...';
      case 'saved':
        return lastSaveTime ? formatDistanceToNow(lastSaveTime, { addSuffix: true }) : 'Saved';
      case 'error':
        return 'Failed';
      default:
        return 'Saved';
    }
  };

  return (
    <>
      {/* Main Footer - Centered Floating Pill */}
      <motion.footer
        initial={{ opacity: 0, y: 50, x: "-50%" }}
        animate={{ opacity: 1, y: 0, x: "-50%" }}
        transition={{ duration: 0.2, ease: [0.4, 0, 0.2, 1] }}
        className="fixed bottom-4 left-1/2 z-30 pointer-events-none"
      >
        <div className="flex items-center justify-center gap-2 px-3 py-1.5 sm:gap-4 sm:px-4 sm:py-2 bg-white/90 dark:bg-surface-dark/90 backdrop-blur-lg rounded-full border border-border-light dark:border-border-dark pointer-events-auto shadow-lg">
          {/* Footer Links - Centered */}
          <div className="flex items-center gap-2 sm:gap-4 text-[10px] sm:text-xs">
            <button
              onClick={() => setShowAboutModal(true)}
              className="text-text-light-secondary dark:text-text-dark-secondary hover:text-accent-blue dark:hover:text-accent-blue-hover transition-all duration-standard ease-smooth whitespace-nowrap"
            >
              About<span className="hidden sm:inline"> Us</span>
            </button>
            <span className="text-border-light dark:text-border-dark">|</span>
            <button
              onClick={() => setShowPrivacyModal(true)}
              className="text-text-light-secondary dark:text-text-dark-secondary hover:text-accent-blue dark:hover:text-accent-blue-hover transition-all duration-standard ease-smooth whitespace-nowrap"
            >
              Privacy<span className="hidden sm:inline"> Policy</span>
            </button>
            <span className="text-border-light dark:text-border-dark">|</span>
            <button
              onClick={() => setShowSupportModal(true)}
              className="text-text-light-secondary dark:text-text-dark-secondary hover:text-accent-magenta dark:hover:text-accent-magenta-hover transition-all duration-standard ease-smooth whitespace-nowrap"
              title="Get help or report issues"
            >
              Help<span className="hidden sm:inline"> & Support</span>
            </button>
            <span className="text-border-light dark:text-border-dark">|</span>
            <span className="text-text-light-secondary dark:text-text-dark-secondary whitespace-nowrap">
              © {new Date().getFullYear()}<span className="hidden sm:inline"> Neuman Brain</span>
            </span>
          </div>

          {/* Save Status (hidden on mobile) - Visually balanced */}
          <div className="hidden sm:flex items-center gap-2 pl-4 border-l border-border-light dark:border-border-dark">
            {/* Status Dot */}
            <span
              className={`w-2.5 h-2.5 rounded-full ${status === 'saving'
                  ? 'bg-blue-500 animate-pulse'
                  : status === 'saved'
                    ? 'bg-green-500'
                    : status === 'error'
                      ? 'bg-red-500'
                      : 'bg-neutral-400'
                }`}
            />

            {/* Status Text */}
            <span className="text-xs font-medium text-text-light-primary dark:text-text-dark-primary whitespace-nowrap">
              {getStatusText()}
            </span>
          </div>
        </div>
      </motion.footer>

      {/* Support Modal */}
      <SupportModal isOpen={showSupportModal} onClose={() => setShowSupportModal(false)} />

      {/* About Modal */}
      {showAboutModal && <AboutModal onClose={() => setShowAboutModal(false)} />}

      {/* Privacy Modal */}
      {showPrivacyModal && <PrivacyModal onClose={() => setShowPrivacyModal(false)} />}
    </>
  );
};

import React, { useEffect, useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';

interface UndoToastProps {
  message: string;
  onUndo: () => void;
  onDismiss: () => void;
  duration?: number; // Auto-dismiss duration in ms (default: 10000)
}

/**
 * UndoToast Component
 * Shows a temporary notification with an undo action
 * Auto-dismisses after specified duration
 */
export const UndoToast: React.FC<UndoToastProps> = ({
  message,
  onUndo,
  onDismiss,
  duration = 10000,
}) => {
  const [timeRemaining, setTimeRemaining] = useState(duration);

  // Countdown timer
  useEffect(() => {
    const interval = setInterval(() => {
      setTimeRemaining((prev) => {
        if (prev <= 100) {
          return 0;
        }
        return prev - 100;
      });
    }, 100);

    return () => clearInterval(interval);
  }, [duration]);

  // Dismiss when time expires (separate effect to avoid setState during render)
  useEffect(() => {
    if (timeRemaining === 0) {
      onDismiss();
    }
  }, [timeRemaining, onDismiss]);

  const handleUndo = () => {
    onUndo();
    onDismiss();
  };

  const progressPercent = (timeRemaining / duration) * 100;

  return (
    <motion.div
      initial={{ opacity: 0, y: 50, scale: 0.9 }}
      animate={{ opacity: 1, y: 0, scale: 1 }}
      exit={{ opacity: 0, scale: 0.9, transition: { duration: 0.2 } }}
      className="fixed bottom-6 right-6 z-50 min-w-[200px] max-w-sm"
    >
      {/* Toast Card */}
      <div className="bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark rounded-button shadow-lg overflow-hidden">
        <div className="flex items-center gap-3 p-3">
          {/* Icon */}
          <div className="flex-shrink-0 w-10 h-10 rounded-full bg-gradient-to-br from-amber-500 to-orange-600 flex items-center justify-center">
            <svg
              className="w-5 h-5 text-white"
              fill="none"
              stroke="currentColor"
              viewBox="0 0 24 24"
            >
              <path
                strokeLinecap="round"
                strokeLinejoin="round"
                strokeWidth={2}
                d="M12 8v4l3 3m6-3a9 9 0 11-18 0 9 9 0 0118 0z"
              />
            </svg>
          </div>

          {/* Message */}
          <div className="flex-1 min-w-0">
            <p className="text-sm text-text-light-primary dark:text-text-dark-primary font-medium truncate">
              {message}
            </p>
            <p className="text-xs text-text-light-secondary dark:text-text-dark-secondary mt-0.5">
              {Math.ceil(timeRemaining / 1000)}s remaining
            </p>
          </div>

          {/* Undo Button */}
          <button
            onClick={handleUndo}
            className="flex-shrink-0 px-4 py-2 rounded-button bg-accent-blue hover:bg-accent-blue-hover text-white text-sm font-medium transition-all duration-200"
          >
            Undo
          </button>

          {/* Close Button */}
          <button
            onClick={onDismiss}
            className="flex-shrink-0 text-text-light-secondary dark:text-text-dark-secondary hover:text-text-light-primary dark:hover:text-text-dark-primary transition-all duration-standard ease-smooth"
            aria-label="Dismiss"
          >
            <svg
              className="w-5 h-5"
              fill="none"
              stroke="currentColor"
              viewBox="0 0 24 24"
            >
              <path
                strokeLinecap="round"
                strokeLinejoin="round"
                strokeWidth={2}
                d="M6 18L18 6M6 6l12 12"
              />
            </svg>
          </button>
        </div>

        {/* Progress Bar */}
        <div className="h-1 bg-neutral-200 dark:bg-neutral-800">
          <motion.div
            className="h-full bg-gradient-to-r from-primary-cyan to-magenta-700"
            initial={{ width: '100%' }}
            animate={{ width: `${progressPercent}%` }}
            transition={{ duration: 0.1, ease: 'linear' }}
          />
        </div>
      </div>
    </motion.div>
  );
};

/**
 * UndoToastContainer Component
 * Manages multiple toast notifications
 */
interface ToastData {
  id: string;
  message: string;
  onUndo: () => void;
}

interface UndoToastContainerProps {
  toasts: ToastData[];
  onDismiss: (id: string) => void;
}

export const UndoToastContainer: React.FC<UndoToastContainerProps> = ({
  toasts,
  onDismiss,
}) => {
  return (
    <div className="fixed bottom-0 right-0 p-6 z-50 pointer-events-none">
      <div className="flex flex-col gap-3 pointer-events-auto">
        <AnimatePresence mode="popLayout">
          {toasts.map((toast, _index) => (
            <UndoToast
              key={toast.id}
              message={toast.message}
              onUndo={toast.onUndo}
              onDismiss={() => onDismiss(toast.id)}
            />
          ))}
        </AnimatePresence>
      </div>
    </div>
  );
};

